// Sun / moon icon for the theme toggle.
function ThemeIcon({ dark, size = 20 }) {
  const common = { width: size, height: size, viewBox: "0 0 24 24", fill: "none", stroke: "currentColor", strokeWidth: 1.7, strokeLinecap: "round", strokeLinejoin: "round", "aria-hidden": true };
  // In dark mode show a sun (tap → light); in light mode show a moon (tap → dark).
  return dark
    ? <svg {...common}><circle cx="12" cy="12" r="4" fill="currentColor" fillOpacity={0.2} /><path d="M12 2.5v2M12 19.5v2M2.5 12h2M19.5 12h2M5 5l1.5 1.5M17.5 17.5L19 19M19 5l-1.5 1.5M6.5 17.5L5 19" /></svg>
    : <svg {...common}><path d="M20 14.5A8 8 0 1 1 9.5 4 6.5 6.5 0 0 0 20 14.5Z" fill="currentColor" fillOpacity={0.18} /></svg>;
}

