// Generates a unique certificate reference for an individual completion.
function genCertId(courseId) {
  const rand = (Date.now().toString(36) + Math.random().toString(36).slice(2)).toUpperCase().replace(/[^A-Z0-9]/g, "");
  return "PCPD-" + String(courseId).slice(0, 4).toUpperCase() + "-" + rand.slice(0, 4) + "-" + rand.slice(4, 8);
}

