          <h2 style={{ fontFamily: "Georgia,serif", fontSize: "1.3rem", color: dm ? "#E8F4FF" : "#0B1F35", marginBottom: "1.25rem", lineHeight: 1.3, borderLeft: "3px solid " + course.color, paddingLeft: ".85rem" }}>{pg.heading}</h2>
