                      <span style={{ width: 25, height: 25, borderRadius: "50%", background: lBg, color: lC, display: "flex", alignItems: "center", justifyContent: "center", fontSize: ".67rem", fontWeight: 700, flexShrink: 0 }}>{letters[oi]}</span>
                      {opt}
