  const allProps = { BookmarksPanel, PRE_QUIZ, PreCourseQuiz, REFS, RevisionMode, S, allBookmarks, baseFs, bg, bookmarks, border, canNext, canvasRef, codeEntryFor, codeError, codeInput, confetti, course, courseComplete, courseFilter, courseSearch, cp, cycleFontSize, darkMode, dm, examAnswers, examDone, examScore, faq, fontSize, goNext, goPrev, goTop, hasFullAccess, hasQuiz, isBookmarked, isCourseUnlocked, isEditingReflection, isLastSlide, markSlide, menuOpen, muted, nameInput, navBg, noteSaveTimer, noteSavedFlash, notepad, openCourse, pages, pendingBuyUrl, pendingCourse, pg, preAnswers, preQuiz, preSubmitted, progress, quizAns, quizDone, reflectInput, reflections, renderBody, revisionAns, revisionDone, revisionIdx, revisionMode, saveName, saveReflection, screen, setBookmarks, setCodeEntryFor, setCodeError, setCodeInput, setConfetti, setCourse, setCourseFilter, setCourseSearch, setDarkMode, setExamAnswers, setExamDone, setExamScore, setFaq, setFontSize, setHasFullAccess, setIsEditingReflection, setMenuOpen, setNameInput, setNoteSavedFlash, setNotepad, setPendingBuyUrl, setPendingCourse, setPreAnswers, setPreQuiz, setPreSubmitted, setProgress, setQuizAns, setQuizDone, setReflectInput, setReflections, setRevisionAns, setRevisionDone, setRevisionIdx, setRevisionMode, setScreen, setShowBookmarks, setShowNameModal, setShowNotepad, setShowRefs, setShowTermsGate, setSlide, setStudySeconds, setTermsAccepted, setTimerActive, setUnlockedCourses, setUserName, showBookmarks, showNameModal, showNotepad, showRefs, showTermsGate, slide, slidesDone, startCourse, startPurchase, studySeconds, submitCode, submitExam, surface, termsAccepted, text, timerActive, timerRef, toggleBookmark, toggleDark, topRef, totalCPD, totalStudyMins, unlockedCourses, userName };

